from itertools import combinations

class Solution:
    def maxRemoval(self, nums, queries):
        m = len(queries)
        n = len(nums)

        def feasible(subset):
            diff = [0] * (n + 1)
            for idx in subset:
                l, r = queries[idx]
                diff[l] += 1
                diff[r + 1] -= 1
            cov = 0
            for i in range(n):
                cov += diff[i]
                if cov < nums[i]:
                    return False
            return True

        best_keep = None
        for size in range(m + 1):
            found = False
            for combo in combinations(range(m), size):
                if feasible(combo):
                    found = True
                    break
            if found:
                best_keep = size
                break
        if best_keep is None:
            return -1
        return m - best_keep

