import heapq

class Solution:
    def maxRemoval(self, nums, queries):
        n = len(nums)
        by_start = [[] for _ in range(n)]
        for l, r in queries:
            by_start[l].append(r)
        avail = []
        chosen_count = 0
        expiry = [0] * (n + 1)
        kept = 0
        for i in range(n):
            chosen_count -= expiry[i]
            for r in by_start[i]:
                heapq.heappush(avail, -r)
            while chosen_count < nums[i]:
                while avail and -avail[0] < i:
                    heapq.heappop(avail)
                if not avail:
                    return -1
                r = -heapq.heappop(avail)
                chosen_count += 1
                kept += 1
                expiry[r + 1] += 1
        return len(queries) - kept

