class MinHeap {
    constructor() { this.a = []; }
    push(x) {
        const a = this.a; a.push(x);
        let i = a.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (a[p] <= a[i]) break;
            [a[p], a[i]] = [a[i], a[p]]; i = p;
        }
    }
    pop() {
        const a = this.a; const top = a[0]; const last = a.pop();
        if (a.length) {
            a[0] = last;
            let i = 0;
            while (true) {
                let l = 2 * i + 1, r = 2 * i + 2, s = i;
                if (l < a.length && a[l] < a[s]) s = l;
                if (r < a.length && a[r] < a[s]) s = r;
                if (s === i) break;
                [a[s], a[i]] = [a[i], a[s]]; i = s;
            }
        }
        return top;
    }
    get size() { return this.a.length; }
    peek() { return this.a[0]; }
}

var maxRemoval = function(nums, queries) {
    const n = nums.length;
    const byStart = Array.from({ length: n }, () => []);
    for (const [l, r] of queries) byStart[l].push(r);
    const avail = new MinHeap();
    let chosenCount = 0;
    const expiry = new Array(n + 1).fill(0);
    let kept = 0;
    for (let i = 0; i < n; i++) {
        chosenCount -= expiry[i];
        for (const r of byStart[i]) avail.push(-r);
        while (chosenCount < nums[i]) {
            while (avail.size && -avail.peek() < i) avail.pop();
            if (!avail.size) return -1;
            const r = -avail.pop();
            chosenCount += 1;
            kept += 1;
            expiry[r + 1] += 1;
        }
    }
    return queries.length - kept;
};
